// Build a mock delivery payload matching the intraday_delivery_payload contract.
// This alert is not written to D1 — it only tests the Telegram and Discord
// delivery paths end to end.
const now = new Date().toISOString();
const dateKey = now.slice(0, 10);

return [{
  json: {
    items: [{
      item_id:          'delivery-smoke-' + Date.now(),
      alert_id:         null,
      cluster_id:       null,
      topic_slug:       'crypto',
      headline:         '[Delivery Smoke Test] Verifying Telegram and Discord — ' + now,
      summary_text:     'Synthetic alert sent by the delivery smoke test workflow to verify that Telegram and Discord channels are correctly wired.',
      source_url:       'https://example.com/delivery-smoke-test',
      source_name:      'Smoke Test',
      severity_score:   50,
      importance_score: 70,
      confidence_score: 99,
      event_at:         now,
      date_key:         dateKey,
      cluster_label:    'Delivery Smoke Test',
      channels:         ['telegram', 'discord']
    }]
  }
}];

// Expand alerts and format Telegram messages.
const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];

const escHtml = (s) =>
  (s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;');

const topicEmoji = {
  crypto: '🪙', finance: '📈', economy: '🏦',
  health: '🏥', ai: '🤖', energy: '⚡', technology: '💻'
};

return items
  .filter(i => (i.channels || []).includes('telegram'))
  .map(item => {
    const emoji = topicEmoji[item.topic_slug] || '📰';
    const importanceBar = '🟩'.repeat(Math.round(item.importance_score / 20))
      + '⬜'.repeat(5 - Math.round(item.importance_score / 20));
    const sourceLink = item.source_url
      ? `\n<a href="${escHtml(item.source_url)}">Source: ${escHtml(item.source_name)}</a>`
      : `\nSource: ${escHtml(item.source_name)}`;
    const text = [
      `${emoji} <b>${item.topic_slug.toUpperCase()}</b>  |  Importance: ${importanceBar} ${item.importance_score}/100`,
      '',
      `<b>${escHtml(item.headline)}</b>`,
      '',
      escHtml(item.summary_text),
      sourceLink
    ].join('\n');
    return { json: { ...item, telegram_text: text } };
  });

// Expand alerts and format Discord embeds.
const input = $('Build Mock Delivery Payload').first().json;
const items = Array.isArray(input.items) ? input.items : [];

const topicColor = {
  crypto: 0xF7931A, finance: 0x2ECC71, economy: 0x3498DB,
  health: 0xE74C3C, ai: 0x9B59B6, energy: 0xF1C40F, technology: 0x1ABC9C
};
const topicEmoji = {
  crypto: '🪙', finance: '📈', economy: '🏦',
  health: '🏥', ai: '🤖', energy: '⚡', technology: '💻'
};

return items
  .filter(i => (i.channels || []).includes('discord'))
  .map(item => {
    const emoji = topicEmoji[item.topic_slug] || '📰';
    const color = topicColor[item.topic_slug] || 0x95A5A6;
    const tsRaw = item.event_at;
    const timestamp = (tsRaw && !isNaN(Date.parse(tsRaw))) ? tsRaw : new Date().toISOString();
    const embed = {
      title: `${emoji} ${item.headline}`,
      description: item.summary_text,
      color,
      fields: [
        { name: 'Topic', value: item.topic_slug.charAt(0).toUpperCase() + item.topic_slug.slice(1), inline: true },
        { name: 'Importance', value: `${item.importance_score}/100`, inline: true },
        { name: 'Severity', value: `${item.severity_score}/100`, inline: true }
      ],
      footer: { text: item.source_name },
      timestamp
    };
    if (item.source_url) embed.url = item.source_url;
    return { json: { ...item, discord_payload: { embeds: [embed] } } };
  });

// Collect results from both delivery channels.
const tgResponse = $('Send Telegram Test').first().json;
const dcResponse = $('Send Discord Test').first().json;

const tgOk = tgResponse.ok === true || !!tgResponse.result?.message_id;
const dcOk = !dcResponse.error && !dcResponse.message;

const summary = {
  telegram: {
    status: tgOk ? 'SUCCESS' : 'FAILED',
    message_id: tgResponse.result?.message_id || null,
    error: tgOk ? null : (tgResponse.description || tgResponse.error || 'Unknown error')
  },
  discord: {
    status: dcOk ? 'SUCCESS' : 'FAILED',
    message_id: dcResponse.id || null,
    error: dcOk ? null : (dcResponse.message || dcResponse.error || 'Unknown error')
  },
  overall: (tgOk && dcOk) ? '✅ Both channels delivered successfully' : '⚠️ One or more channels failed — check details above'
};

console.log(JSON.stringify(summary, null, 2));
return [{ json: summary }];
